/**
 * Searches the tide table for the next high tide occurring after the given time.
 * @planks("I ask for the next high tide after {string}")
 * @param {Array} tides - Array of tide entries with time, type, and height fields
 * @param {string} after - ISO 8601 timestamp to search from
 * @returns {Object} The next high tide entry
 * @throws {Error} When no upcoming high tide exists in the data
 */
function nextHighTide(tides, after) {
  const next = tides.find((t) => new Date(t.time) > new Date(after) && t.type === "high");
  if (!next) throw new Error("no upcoming high tide in data");
  return next;
}

module.exports = { nextHighTide };

